import React from "react";
import ReactDom from "react-dom/client";
import "./index.css";

function App() {
  return (
    <div className="card">
      <Img />
      <div className="data"></div>
    </div>
  );
}

function Img() {
  return (
    <div>
      <img src="./my-photo.jpg" alt="a guy looking at the camera" />
    </div>
  );
}

const rootElement = document.getElementById("root");
const root = ReactDom.createRoot(rootElement);

root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
);
